package com.allthinkstars.framework.iot.app.service.impl;

import com.allthinkstars.framework.iot.app.dto.PlanQueryParam;
import com.allthinkstars.framework.iot.app.service.AppProdPlanService;
import com.allthinkstars.framework.iot.app.service.AppUserDeptService;
import com.allthinkstars.framework.iot.business.util.PageUtils;
import com.allthinkstars.framework.iot.erp.datasource.entities.TbProdPlan;
import com.allthinkstars.framework.iot.erp.datasource.entities.TbProdPlanFurnace;
import com.allthinkstars.framework.iot.erp.datasource.mappers.TbProdPlanFurnaceMapper;
import com.allthinkstars.framework.iot.erp.datasource.mappers.TbProdPlanMapper;
import com.allthinkstars.framework.iot.erp.entity.TbCastingProductionPlan;
import com.allthinkstars.framework.iot.erp.vo.CastingProductionPlanPageVo;
import com.allthinkstars.framework.iot.nextg.entity.TbDeviceFurnace;
import com.allthinkstars.framework.iot.nextg.support.DeviceFurnaceSupport;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.core.toolkit.Wrappers;
import com.baomidou.mybatisplus.core.toolkit.support.SFunction;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.ruoyi.common.core.domain.PageQuery;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.stereotype.Service;

import java.util.Objects;


@Service
@Slf4j
@RequiredArgsConstructor
public class AppProdPlanServiceImpl implements AppProdPlanService {

    private final TbProdPlanMapper tbProdPlanMapper;
    private final AppUserDeptService appUserDeptService;
    private final DeviceFurnaceSupport deviceFurnaceSupport;
    private final TbProdPlanFurnaceMapper tbProdPlanFurnaceMapper;


    @Override
    public IPage<CastingProductionPlanPageVo> queryPlanPageList(PlanQueryParam dto, PageQuery pageQuery) {

        TbProdPlan condition = new TbProdPlan();

        var wrapper = Wrappers.lambdaQuery(condition)
            .ge(Objects.nonNull(dto.getStartDate()),
                TbProdPlan::getPlanDate,
                dto.getStartDate())
            .le(Objects.nonNull(dto.getEndDate()),
                TbProdPlan::getPlanDate,
                dto.getEndDate())
            .eq(Objects.nonNull(dto.getDeviceInternalId()),
                TbProdPlan::getDeviceInternalId,
                dto.getDeviceInternalId())
            .eq(Objects.nonNull(dto.getFurnaceNo()),
                TbProdPlan::getFurnaceNo,
                dto.getFurnaceNo())
            .eq(Objects.nonNull(dto.getFurnaceCode()),
                TbProdPlan::getFurnaceCode,
                dto.getFurnaceCode())
            .eq(Objects.nonNull(dto.getOrderId()),
                TbProdPlan::getOrderNum,
                dto.getOrderId())
            .eq(Objects.nonNull(dto.getStatus()),
                TbProdPlan::getStatus,
                dto.getStatus())
            .orderByDesc((SFunction<TbProdPlan, Object>) TbProdPlan::getShiftBeginAt);

        Long deptId = appUserDeptService.getDeptId();
        wrapper.eq(TbProdPlan::getTenantId,deptId);

        if(StringUtils.isNotBlank(dto.getKeyword())){
            wrapper.and(q->{
               q.eq(TbProdPlan::getFurnaceNo,dto.getKeyword()).or()
                   .eq(TbProdPlan::getFurnaceCode,dto.getKeyword());
            });
        }
        Page<TbProdPlan> page = tbProdPlanMapper.selectPage(pageQuery.build(), wrapper);
        return PageUtils.toPage(page, i -> {
            CastingProductionPlanPageVo vo = new CastingProductionPlanPageVo();
            vo.setPlanId(i.getId());
            vo.setPlanDate(i.getPlanDate());
            vo.setShiftBeginAt(i.getShiftBeginAt());
            vo.setShiftEndAt(i.getShiftEndAt());
            vo.setDeviceInternalId(i.getDeviceInternalId());
            vo.setFurnaceNo(i.getFurnaceNo());
            vo.setFurnaceCode(i.getFurnaceCode());
            vo.setOrderId(i.getOrderId());
            vo.setStatus(i.getStatus());
            vo.setLadleBatchCountTarget(i.getLadleBatchCountTarget());
            vo.setBatchCountActual(i.getBatchCountActual());
            vo.setOperator(i.getOperator());
            vo.setOrderNum(i.getOrderNum());
            vo.setStatus(i.getStatus());
            vo.setStatusName(Objects.requireNonNull(TbProdPlan.PlanStatusEnum.of(i.getStatus())).getValueName());
            vo.setContent(i.getContent());
            Long count = tbProdPlanFurnaceMapper.selectCount(Wrappers.<TbProdPlanFurnace>lambdaQuery()
                .eq(TbProdPlanFurnace::getPlanId, i.getId()));
            TbDeviceFurnace tbDeviceFurnace = deviceFurnaceSupport.getFurnaceThrowable(i.getFurnaceCode(), i.getDeviceInternalId());
            if (tbDeviceFurnace != null) {
                vo.setFurnaceName(tbDeviceFurnace.getCustomFnName());
            }
            vo.setFurnaceCount(count);
            vo.setDefaultPlan(i.isDefaultPlan());
            return vo;
        });
    }


}

