    private static String inferJsonType(Class<?> type) {
        if (type == null) {
            return "string";
        }
        if (CharSequence.class.isAssignableFrom(type) || type == Character.class || type == char.class) {
            return "string";
        }
        if (type == boolean.class || type == Boolean.class) {
            return "boolean";
        }
        if (type.isArray() || java.util.Collection.class.isAssignableFrom(type)) {
            return "array";
        }
        if (type == float.class || type == double.class || type == java.math.BigDecimal.class) {
            return "number";
        }
        if (Number.class.isAssignableFrom(type)
            || type == byte.class || type == short.class || type == int.class || type == long.class) {
            return "integer";
        }
        if (JsonNode.class.isAssignableFrom(type)
            || java.util.Map.class.isAssignableFrom(type)
            || type == Object.class) {
            return "object";
        }
        return "string";
    }

