    private QueryFurnaceReportVo findReportItem(DeviceFurnaceReport report, Long batchId, Integer batchNo) {
        if (report == null || report.getRecordList() == null) {
            return null;
        }
        String expectedBatchId = batchId == null ? null : String.valueOf(batchId);
        for (QueryFurnaceReportVo item : report.getRecordList()) {
            if (item == null) {
                continue;
            }
            if (expectedBatchId != null && expectedBatchId.equals(item.getBatchId())) {
                return item;
            }
            if (expectedBatchId == null && batchNo != null && Objects.equals(batchNo, item.getBatchNo())) {
                return item;
            }
        }
        return null;
    }

