        if (!didList.isEmpty()) {
            source.addAll(tbDeviceFurnaceMapper.selectListByDidList(didList));
        }
        List<Long> deptIds = resolveVisibleDeptIds(ctx);
        for (Long deptId : deptIds) {
            if (deptId == null) {
                continue;
            }
            List<TbDeviceFurnace> furnaces = tbDeviceFurnaceMapper.selectAllByFactory(deptId);
            if (furnaces != null && !furnaces.isEmpty()) {
                source.addAll(furnaces);
            }
        }
        for (TbDeviceFurnace furnace : source) {
            if (furnace == null) {
                continue;
            }
            if (Objects.equals(furnace.getDeviceInternalId(), did) && Objects.equals(furnace.getFnNo(), fnNo)) {
                return furnace;
            }
        }
        return null;
    }

    private boolean isVisibleBatch(TbCastingFurnaceChargeBatch batch, List<Long> didList, List<Long> deptIds) {
        if (batch == null) {
            return false;
        }
        boolean visibleByDid = batch.getDeviceInternalId() != null && didList.contains(batch.getDeviceInternalId());
        boolean visibleByDept = batch.getDeptId() != null && deptIds.contains(batch.getDeptId());
        return visibleByDid || visibleByDept;
    }

    private ObjectNode buildDetailQuery(String batchId, String fnCode, LocalDate date, Integer batchNo) {
        ObjectNode query = objectMapper.createObjectNode();
        putNullableText(query, "batchId", batchId);
        putNullableText(query, "fnCode", fnCode);
        putNullableText(query, "date", date == null ? null : date.toString());
        putNullableInt(query, "batchNo", batchNo);
        return query;
    }

    private ArrayNode summarizeChargeRecords(List<TbCastingProductionBatch.FurnaceChargeRecord> records) {
        Map<String, BigDecimal> sums = new LinkedHashMap<>();
        Map<String, String> units = new LinkedHashMap<>();
        if (records != null) {
            for (TbCastingProductionBatch.FurnaceChargeRecord record : records) {
                if (record == null || record.getRecord() == null || record.getRecord().getName() == null) {
                    continue;
                }
                String name = record.getRecord().getName();
                BigDecimal actual = record.getRecord().getActual() == null ? BigDecimal.ZERO : record.getRecord().getActual();
                sums.merge(name, actual, BigDecimal::add);
                if (record.getRecord().getUnit() != null) {
                    units.putIfAbsent(name, record.getRecord().getUnit());
                }
            }
        }
        ArrayNode array = objectMapper.createArrayNode();
        sums.forEach((name, actual) -> {
            ObjectNode item = objectMapper.createObjectNode();
            item.put("name", name);
            item.put("actual", actual.toPlainString());
            putNullableText(item, "unit", units.get(name));
            array.add(item);
        });
        return array;
    }

    private ArrayNode detailChargeRecords(List<TbCastingProductionBatch.FurnaceChargeRecord> records) {
        ArrayNode array = objectMapper.createArrayNode();
        if (records == null) {
            return array;
        }
        for (TbCastingProductionBatch.FurnaceChargeRecord record : records) {
            if (record == null || record.getRecord() == null) {
                continue;
            }
            array.add(objectMapper.valueToTree(record.getRecord()));
        }
        return array;
    }

    private JsonNode toJsonArray(Object value) {
        if (value == null) {
            return objectMapper.createArrayNode();
        }
        JsonNode node = objectMapper.valueToTree(value);
        return node == null || node.isNull() ? objectMapper.createArrayNode() : node;
    }

    private String normalizeText(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }

    private BigDecimal sumWeightRecords(List<TbCastingProductionBatch.WeightRecord> records) {
        if (records == null || records.isEmpty()) {
            return BigDecimal.ZERO;
        }
        return records.stream()
            .filter(Objects::nonNull)
            .map(TbCastingProductionBatch.WeightRecord::getActual)
            .filter(Objects::nonNull)
            .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private List<TbDeviceFurnace> findFurnacesByFnCode(AiRunContext ctx, String fnCode) {
        List<TbDeviceFurnace> source = new ArrayList<>();
        List<Long> didList = resolveVisibleDeviceIds(ctx);
        if (!didList.isEmpty()) {
            source.addAll(tbDeviceFurnaceMapper.selectListByDidList(didList));
        }

        List<Long> deptIds = resolveVisibleDeptIds(ctx);
        for (Long deptId : deptIds) {
            if (deptId == null) {
                continue;
            }
            List<TbDeviceFurnace> furnaces = tbDeviceFurnaceMapper.selectAllByFactory(deptId);
            if (furnaces != null && !furnaces.isEmpty()) {
                source.addAll(furnaces);
            }
        }

        if (source.isEmpty()) {
            return Collections.emptyList();
        }

        String normalizedFnCode = fnCode.trim();
        Map<String, TbDeviceFurnace> unique = new LinkedHashMap<>();
        for (TbDeviceFurnace furnace : source) {
            if (furnace == null || furnace.getFnCode() == null) {
                continue;
            }
            if (!normalizedFnCode.equalsIgnoreCase(furnace.getFnCode().trim())) {
                continue;
            }
            String uniqueKey = furnace.getFurnaceId();
            if (uniqueKey == null) {
                uniqueKey = furnace.getDeviceInternalId() + "|" + furnace.getFnNo();
            }
            unique.putIfAbsent(uniqueKey, furnace);
        }
        return new ArrayList<>(unique.values());
    }

    private static String formatDateTime(LocalDateTime t) {
        return t == null ? null : t.toString();
    }

    private static List<Long> resolveVisibleDeviceIds(AiRunContext ctx) {
        if (ctx == null || ctx.getVisibleDeviceInternalIds() == null) {
            return Collections.emptyList();
        }
        return ctx.getVisibleDeviceInternalIds();
    }

    private static List<Long> resolveVisibleDeptIds(AiRunContext ctx) {
        if (ctx == null) {
            return Collections.emptyList();
        }
        List<Long> deptIds = ctx.getVisibleDeptIds();
        if (deptIds != null && !deptIds.isEmpty()) {
            return deptIds;
        }
        if (ctx.getTenantId() != null) {
            return Collections.singletonList(ctx.getTenantId());
        }
        return Collections.emptyList();
    }
}

