class ToolArgsValidationResult(BaseModel):
    tool_name: str = ""
    schema_version: str = "v1"
    normalized_args: dict[str, Any] = Field(default_factory=dict)
    missing_args: list[str] = Field(default_factory=list)
    unknown_args: list[str] = Field(default_factory=list)
    invalid_args: list[str] = Field(default_factory=list)
    missing_fields: list[ClarificationField] = Field(default_factory=list)

    @property
    def is_valid(self) -> bool:
        return not (self.missing_args or self.unknown_args or self.invalid_args)

    def to_validation_errors(self) -> list[str]:
        errors = [f"missing_arg:{key}" for key in self.missing_args]
        errors.extend(f"unknown_arg:{key}" for key in self.unknown_args)
        errors.extend(f"invalid_arg:{key}" for key in self.invalid_args)
        if not self.is_valid and self.tool_name:
            errors.append(f"tool_arguments_invalid:{self.tool_name}")
        return errors

    def to_error_payload(self, *, message: str) -> ToolValidationErrorPayload:
        return ToolValidationErrorPayload(
            error_code="invalid_tool_arguments",
            tool_name=self.tool_name,
            schema_version=self.schema_version,
            message=message,
            missing_args=list(self.missing_args),
            unknown_args=list(self.unknown_args),
            invalid_args=list(self.invalid_args),
        )

    def to_clarification_context(self, *, question: str, reason: str) -> ClarificationContext:
        return ClarificationContext(
            question=question,
            reason=reason,
            tool_name=self.tool_name,
            missing_fields=[field.model_copy() for field in self.missing_fields],
        )


class ToolRuntime:
    """统一暴露每轮工具快照、参数校验与执行入口。"""

    def __init__(self, backend) -> None:
        self._backend = backend

    async def load(self, *, dept_id: str, user_id: str) -> ToolCatalogSnapshot:
        descriptors = await self._backend.list_tools(dept_id=dept_id, user_id=user_id)
        return ToolCatalogSnapshot(
            descriptors=[
                item if isinstance(item, ToolDescriptor) else ToolDescriptor.from_raw(item)
                for item in descriptors
                if isinstance(item, (ToolDescriptor, dict))
            ]
        )

    def get(self, snapshot: ToolCatalogSnapshot, tool_name: str) -> ToolDescriptor | None:
        for descriptor in snapshot.descriptors:
