        self,
        *,
        snapshot: ToolCatalogSnapshot,
        tool_name: str,
        arguments: dict[str, Any],
        user_query: str,
    ) -> tuple[ToolDescriptor | None, ToolArgsValidationResult | None]:
        descriptor = self.get(snapshot, tool_name)
        if descriptor is None:
            return None, None
        validation = ToolRuntime.validate_descriptor(descriptor, arguments, user_query=user_query)
        return descriptor, validation

    async def execute(
        self,
        *,
        snapshot: ToolCatalogSnapshot,
        conversation_id: str,
        dept_id: str,
        user_id: str,
        tool_name: str,
        arguments: dict[str, Any],
        schema_version: str,
    ) -> ToolExecutionResult:
        tool_call_id = uuid4().hex
        result = await self._backend.call_tool(
            tool_name=tool_name,
            args=arguments,
            conversation_id=conversation_id,
            tool_call_id=tool_call_id,
            tenant_id=dept_id,
            user_id=user_id,
        )
        return ToolExecutionResult(
            tool_name=tool_name,
            arguments=dict(arguments),
            call_result=result,
