def _unique_categories(matches: list[_RuleMatch]) -> list[str]:
    seen: set[str] = set()
    categories: list[str] = []
    for match in matches:
        if match.category in seen:
            continue
        seen.add(match.category)
        categories.append(match.category)
    return categories


