import java.util.function.Supplier;

/**
 * 为 AI tool 调用临时建立线程内 LoginUser 上下文，
 * 仅覆盖依赖 LoginHelper.getLoginUser()/getUserId() 的存量业务逻辑。
 */
@RequiredArgsConstructor
public class SaTokenAiToolLoginContextRunner implements AiToolLoginContextRunner {

    private final ISysUserService sysUserService;
    private final LoginSupport loginSupport;

    @Override
    public <T> T run(AiRunContext runContext, Supplier<T> action) {
        if (runContext == null || runContext.getSysUserId() == null) {
            return action.get();
        }
        SysUser user = sysUserService.selectUserById(runContext.getSysUserId());
        Assert.notNull(user, "AI tool run-as user not found: " + runContext.getSysUserId());

        LoginUser loginUser = loginSupport.buildLoginUser(user);
        SaHolder.getStorage().set(LoginHelper.LOGIN_USER_KEY, loginUser);
        try {
            return action.get();
        } finally {
            SaHolder.getStorage().set(LoginHelper.LOGIN_USER_KEY, null);
        }
    }
}

