     * @return 当前用户选择的工厂 ID
     */
    public Long getFactoryDeptId() {
        LoginUser loginUser = Objects.requireNonNull(LoginHelper.getLoginUser());
        Long depId = null;
        if (Objects.equals(loginUser.getDebugPrivilege(), 1)) {
            TbDebugUserCut tbDebugUserCut = tbDebugUserCutMapper.selectOne(
                Wrappers.lambdaQuery(TbDebugUserCut.class)
                    .eq(TbDebugUserCut::getSysUserId, loginUser.getUserId())
            );
            if (Objects.nonNull(tbDebugUserCut)) {
                depId = tbDebugUserCut.getDeptId();
            }
        }
        depId = Optional.ofNullable(depId)
            .orElseGet(() -> sysDeptMapper.selectFactoryDeptByDeptId(loginUser.getDeptId()).getDeptId());
        return Objects.requireNonNull(depId);
    }


    /**
     * 获取当前用户可见的所有工厂的所有设备的DID
     * @return 当前用户可见的所有工厂的所有设备的DID
     */
    public List<Long> getUserVisibleDidList(){
        List<TbDeviceUserDeptRelationBo> records = getCurrentUserDeptRelations();
        if (records == null) {
            return new ArrayList<>();
        }

        return records.stream()
            .map(TbDeviceUserDeptRelationBo::getDeviceInternalId)
            .filter(Objects::nonNull)
            .collect(Collectors.toList());
    }

    /**
     * 获取当前用户可见设备的所有设备炉体
     * @return 用户可选择的所有设备炉体
     */
    public List<TbDeviceFurnace> getUserVisibleDeviceFurnaces(){
        List<Long> didList = getUserVisibleDidList();
        if (CollectionUtils.isEmpty(didList)){
            return new ArrayList<>();
        }
        return tbDeviceFurnaceMapper.selectListByDidList(didList);
    }

