     * @return 当前用户可见的所有工厂的关联关系
     */
    public List<TbDeviceUserDeptRelationBo> getCurrentUserDeptRelations() {
        SysUser user = sysUserMapper.getCurrentSysUser();
        if (Objects.isNull(user)) {
            return null;
        }

        SysDept factoryDeptById = sysDeptMapper.selectFactoryDeptById(user.getDeptId());
        Integer deptType = user.getDept().getDeptType();
        if (Objects.nonNull(factoryDeptById)) {
            deptType = factoryDeptById.getDeptType();
        }
        PageQueryDeviceParam param = new PageQueryDeviceParam();
        param.setDeptId(user.getDeptId());
        param.setUserId(user.getUserId());
        param.setDeptType(deptType);
        param.setCustomUserType(user.getCustomUserType());
        param.setFindType(0);
        if (user.getDebugPrivilege() == 1) {
            TbDebugUserCut tbDebugUserCut = tbDebugUserCutMapper.selectOne(
                Wrappers.lambdaQuery(TbDebugUserCut.class)
                    .eq(TbDebugUserCut::getSysUserId, user.getUserId())
            );
            if (Objects.nonNull(tbDebugUserCut)){
                param.setSelectDeptId(tbDebugUserCut.getDeptId());
            }
        }

        IPage<TbDeviceUserDeptRelationBo> page = tbDeviceUserDeptRelationMapper.selectUserDeptDevList(new PageQuery().build(), param);
        return page.getTotal() == 0 ? new ArrayList<>() : page.getRecords();
    }

    /**
