        if (page.getTotal() == 0) {
            return new ArrayList<>();
        }
        return page.getRecords().stream()
            .map(TbDeviceUserDeptRelationBo::getDeviceInternalId)
            .filter(Objects::nonNull)
            .collect(Collectors.toList());
    }

