    public void invoke_shouldUnwrapInvocationTargetExceptionCause() {
        ToolRegistry registry = new ToolRegistry();
        registry.registerAnnotatedBean(new ObjectMapper(), new DemoTools());

        ObjectNode args = new ObjectMapper().createObjectNode();
        args.put("name", "x");

        IllegalStateException ex = Assert.assertThrows(IllegalStateException.class,
            () -> registry.invoke("boom_tool", args, new AiRunContext()));
