/**
 * 分页工具类
 */
public class PageUtils {
    private PageUtils() {
    }

    public static <S, T> Page<T> toPage(IPage<S> pageInput, List<T> list) {
        Page<T> pageOutput = new Page<>(pageInput.getCurrent(), pageInput.getSize(), pageInput.getTotal());
        pageOutput.setRecords(list);
        return pageOutput;
    }

    public static <S, T> Page<T> toPage(IPage<S> pageInput, Function<S, T> function) {
        Page<T> pageOutput = new Page<>(pageInput.getCurrent(), pageInput.getSize(), pageInput.getTotal());
        pageOutput.setRecords(pageInput.getRecords().stream().map(function).collect(Collectors.toList()));
        return pageOutput;
    }

    public static <S> Page<S> toPage(IPage<S> pageInput) {
        Page<S> pageOutput = new Page<>(pageInput.getCurrent(), pageInput.getSize(), pageInput.getTotal());
        pageOutput.setRecords(pageInput.getRecords());
        return pageOutput;
    }

    public static <S, T> Page<T> empty() {
        Page<T> pageOutput = new Page<>(0, 0, 0);
        pageOutput.setRecords(List.of());
        return pageOutput;
    }

