import com.allthinkstars.framework.iot.erp.vo.CastingProductionPlanPageVo;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import com.ruoyi.common.core.domain.PageQuery;
import lombok.RequiredArgsConstructor;
import org.apache.commons.lang3.StringUtils;

import java.time.LocalDate;
import java.util.List;
import java.util.Objects;

/**
 * 生产计划 AI 工具。
 * 这里复用现有计划查询与详情服务，只在工具层完成参数映射和 AI 友好的结果裁剪。
 */
@RequiredArgsConstructor
@AiToolComponent
public class AiProductionPlanTools {

    private static final int DEFAULT_LIMIT = 5;
    private static final int MAX_LIMIT = 20;

    private final AppProdPlanService appProdPlanService;
    private final CastingProductionPlanManageService planManageService;
    private final ObjectMapper objectMapper;

    @AiToolDef("查询当前工厂内的生产计划列表。适用于按计划名称、炉号、日期范围或状态筛选计划。")
    public ToolResult production_plan_search(
        @AiToolParam(
            name = "planName",
            value = "计划名称，可选；用于按计划名称筛选。",
            title = "计划名称",
            examples = {"白班计划", "球铁计划"}
        ) String planName,
        @AiToolParam(
            name = "fnCode",
            value = "工厂炉号编码，可选；等价于现有计划查询中的 furnaceCode。",
            title = "炉号",
            examples = {"A01", "1", "2"}
        ) String fnCode,
        @AiToolParam(
            name = "startDate",
            value = "查询起始日期，格式 YYYY-MM-DD。",
            title = "开始日期",
            examples = {"2026-03-17"}
        ) String startDate,
        @AiToolParam(
            name = "endDate",
            value = "查询结束日期，格式 YYYY-MM-DD。",
            title = "结束日期",
            examples = {"2026-03-17"}
        ) String endDate,
        @AiToolParam(
            name = "status",
            value = "生产计划状态，可选。0=待生产，1=生产中，2=生产完成。",
            title = "计划状态",
            examples = {"0", "1", "2"}
        ) Integer status,
        @AiToolParam(
            name = "limit",
            value = "最多返回多少条计划，不传默认 5，最大 20。",
            title = "返回数量上限",
            examples = {"5", "10"}
        ) Integer limit,
        AiRunContext ctx
    ) {
        // 搜索工具只负责把 AI 参数映射到既有查询服务，避免维护第二套计划查询逻辑。
        PlanQueryParam queryParam = new PlanQueryParam();
        queryParam.setPlanName(normalizeText(planName));
        queryParam.setKeyword(normalizeText(fnCode));
        queryParam.setStartDate(parseDate(startDate, "startDate"));
        queryParam.setEndDate(parseDate(endDate, "endDate"));
        queryParam.setStatus(status);

        PageQuery pageQuery = new PageQuery();
        pageQuery.setPageNum(1);
        pageQuery.setPageSize(normalizeLimit(limit));

        IPage<CastingProductionPlanPageVo> page = appProdPlanService.queryPlanPageList(queryParam, pageQuery);
        ObjectNode data = objectMapper.createObjectNode();
        data.put("count", page.getRecords().size());
        data.put("total", page.getTotal());
        ArrayNode items = objectMapper.createArrayNode();
        for (CastingProductionPlanPageVo plan : page.getRecords()) {
            items.add(toSearchItem(plan));
        }
        data.set("items", items);

        String preview = buildSearchPreview(page.getRecords());
        return ToolResult.ok(preview, data);
    }

    @AiToolDef("查询单个生产计划详情，返回计划主信息和炉次计划摘要。")
    public ToolResult production_plan_detail(
        @AiToolParam(
            name = "planId",
            value = "生产计划唯一 ID。",
            title = "计划ID",
            examples = {"12345"},
            required = true
        ) Long planId,
        AiRunContext ctx
    ) {
        // 详情继续复用既有 DTO 查询链路，但对返回结果做摘要裁剪，避免把包次重字段提前暴露给模型。
        CastingProductionPlanDto detail = planManageService.planDetail(planId);
        if (detail == null || detail.getPlanId() == null) {
            return ToolResult.fail("tool_exec_failed", "未找到对应生产计划，planId=" + planId);
        }

        ObjectNode data = objectMapper.createObjectNode();
        putNullableLong(data, "planId", detail.getPlanId());
        putNullableText(data, "planName", detail.getPlanName());
        putNullableText(data, "planDate", detail.getPlanDate() == null ? null : detail.getPlanDate().toString());
        putNullableText(data, "shiftBeginAt", detail.getShiftBeginAt() == null ? null : detail.getShiftBeginAt().toString());
        putNullableText(data, "shiftEndAt", detail.getShiftEndAt() == null ? null : detail.getShiftEndAt().toString());
        putNullableText(data, "furnaceCode", detail.getFurnaceCode());
        putNullableText(data, "orderNum", detail.getOrderNum());
        putNullableInt(data, "status", detail.getStatus());
        putNullableText(data, "statusName", statusName(detail.getStatus()));
        putNullableText(data, "operator", detail.getOperator());
        putNullableText(data, "content", detail.getContent());
        putNullableInt(data, "ladleBatchCountTarget", detail.getLadleBatchCountTarget());
        data.set("furnacePlans", toFurnacePlanSummary(detail.getFurnacePlans()));

        String preview = "planId=" + detail.getPlanId()
            + ", planName=" + safeText(detail.getPlanName())
            + ", furnacePlans=" + (detail.getFurnacePlans() == null ? 0 : detail.getFurnacePlans().size());
        return ToolResult.ok(preview, data);
    }

    private ArrayNode toFurnacePlanSummary(List<CastingProductionPlanDto.FurnacePlan> furnacePlans) {
        ArrayNode array = objectMapper.createArrayNode();
        if (furnacePlans == null) {
            return array;
        }
        for (CastingProductionPlanDto.FurnacePlan furnacePlan : furnacePlans) {
            if (furnacePlan == null) {
                continue;
            }
            ObjectNode item = objectMapper.createObjectNode();
            putNullableLong(item, "furnacePlanId", furnacePlan.getId());
            putNullableInt(item, "batchNo", furnacePlan.getBatchNo());
            putNullableLong(item, "recipeId", furnacePlan.getRecipeId());
            putNullableText(item, "recipeName", furnacePlan.getRecipeName());
            if (furnacePlan.getPlanTotalWeight() != null) {
                item.put("planTotalWeight", furnacePlan.getPlanTotalWeight().toPlainString());
            } else {
                item.putNull("planTotalWeight");
            }
            putNullableInt(item, "ladleCount", furnacePlan.getLadlePlans() == null ? 0 : furnacePlan.getLadlePlans().size());
            array.add(item);
        }
        return array;
    }

    private ObjectNode toSearchItem(CastingProductionPlanPageVo plan) {
        ObjectNode item = objectMapper.createObjectNode();
        putNullableLong(item, "planId", plan.getPlanId());
        putNullableText(item, "planName", plan.getPlanName());
        putNullableText(item, "planDate", plan.getPlanDate() == null ? null : plan.getPlanDate().toString());
        putNullableText(item, "shiftBeginAt", plan.getShiftBeginAt() == null ? null : plan.getShiftBeginAt().toString());
        putNullableText(item, "shiftEndAt", plan.getShiftEndAt() == null ? null : plan.getShiftEndAt().toString());
        putNullableText(item, "furnaceCode", plan.getFurnaceCode());
        putNullableText(item, "orderNum", plan.getOrderNum());
        putNullableInt(item, "status", plan.getStatus());
        putNullableText(item, "statusName", plan.getStatusName());
        putNullableText(item, "operator", plan.getOperator());
        putNullableText(item, "content", plan.getContent());
        putNullableInt(item, "ladleBatchCountTarget", plan.getLadleBatchCountTarget());
        return item;
    }

    private String buildSearchPreview(List<CastingProductionPlanPageVo> records) {
        if (records == null || records.isEmpty()) {
            return "未找到匹配的生产计划";
        }
        CastingProductionPlanPageVo first = records.get(0);
        return "找到" + records.size() + "条生产计划"
            + "，首条 planId=" + first.getPlanId()
            + "，furnaceCode=" + safeText(first.getFurnaceCode())
            + "，status=" + safeText(first.getStatusName());
    }

    private int normalizeLimit(Integer limit) {
        if (limit == null || limit <= 0) {
            return DEFAULT_LIMIT;
        }
        return Math.min(limit, MAX_LIMIT);
    }

    private LocalDate parseDate(String raw, String fieldName) {
        String normalized = normalizeText(raw);
        if (normalized == null) {
            return null;
        }
        try {
            return LocalDate.parse(normalized);
        } catch (Exception e) {
            throw new IllegalArgumentException("参数类型不匹配: " + fieldName);
        }
    }

    private String statusName(Integer status) {
        TbProdPlan.PlanStatusEnum statusEnum = TbProdPlan.PlanStatusEnum.of(status);
        return statusEnum == null ? null : statusEnum.getValueName();
    }

    private String normalizeText(String value) {
        if (StringUtils.isBlank(value)) {
            return null;
        }
        return value.trim();
    }

    private String safeText(String value) {
        return Objects.toString(value, "-");
    }

    private void putNullableText(ObjectNode node, String field, String value) {
        if (value == null) {
            node.putNull(field);
            return;
        }
        node.put(field, value);
    }

    private void putNullableInt(ObjectNode node, String field, Integer value) {
        if (value == null) {
            node.putNull(field);
            return;
        }
        node.put(field, value);
    }

    private void putNullableLong(ObjectNode node, String field, Long value) {
        if (value == null) {
            node.putNull(field);
            return;
        }
        node.put(field, value);
    }
}

